import (
	"context"
	"github.com/openmeterio/openmeter/collector/benthos/internal/message"
)

func process(batch message.Batch) error {
	tx := message.NewTransactionFunc(batch, func(ctx context.Context, err error) error {
		return err
	})
	// ... pipeline stages ...
	return tx.Ack(context.Background(), nil)
}

import "github.com/openmeterio/openmeter/collector/benthos/internal/shutdown"

sig := shutdown.NewSignaller()
go func() {
	defer sig.ShutdownComplete()
	for {
		select {
		case <-sig.CloseAtLeisureChan():
			// finish in-flight work, then return
			return
		}
	}
}()
// orchestrator triggers and waits
sig.CloseNow()
<-sig.HasClosedChan()
